import React from 'react';
import {
  User,
  Briefcase,
  Wrench,
  Award,
  Mail,
} from 'lucide-react';
import { Dock, DockIcon, DockItem, DockLabel } from '../components/ui/dock';

interface HomeProps {
  navigate: (page: string) => void;
}

const dockItems = [
  { title: 'About Me',      icon: User,      page: 'about' },
  { title: 'Experience',    icon: Briefcase,  page: 'experience' },
  { title: 'Skills',        icon: Wrench,     page: 'skills' },
  { title: 'Certifications',icon: Award,      page: 'certifications' },
  { title: 'Contact',       icon: Mail,       page: 'contact' },
];

const Home: React.FC<HomeProps> = ({ navigate }) => {
  return (
    <div style={{
      display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
      height: '100%', padding: 40, textAlign: 'center',
      background: `
        radial-gradient(ellipse 60% 80% at 50% 50%, rgba(255,255,180,0.18) 0%, transparent 60%),
        radial-gradient(circle at 15% 25%, rgba(180,220,220,0.13) 0%, transparent 35%),
        radial-gradient(circle at 80% 20%, rgba(200,180,220,0.10) 0%, transparent 30%),
        radial-gradient(circle at 70% 75%, rgba(180,220,200,0.10) 0%, transparent 30%),
        radial-gradient(circle at 25% 75%, rgba(220,200,180,0.10) 0%, transparent 30%),
        #f0eeeb
      `,
      position: 'relative',
    }}>
      <h1 style={{ fontSize: 88, fontFamily: '"Abril Fatface", Georgia, serif', fontWeight: 400, marginBottom: 14, lineHeight: 1, color: '#1a1a1a' }}>
        Raghv Bhatia
      </h1>
      <h2 style={{ fontSize: 26, fontWeight: 'normal', fontFamily: '"Playfair Display", Georgia, serif', color: '#333', marginBottom: 80, letterSpacing: 1 }}>
        Digital Experience Partner
      </h2>

      {/* Dock navigation */}
      <div className="absolute bottom-4 left-1/2 -translate-x-1/2 w-full max-w-full px-4">
        <Dock className="items-end pb-3" magnification={72} panelHeight={56}>
          {dockItems.map((item) => {
            const Icon = item.icon;
            return (
              <DockItem
                key={item.page}
                className="aspect-square rounded-full bg-white/80 shadow-sm border border-gray-200 cursor-pointer"
                onClick={() => navigate(item.page)}
              >
                <DockLabel>{item.title}</DockLabel>
                <DockIcon>
                  <Icon className="h-full w-full text-neutral-600" />
                </DockIcon>
              </DockItem>
            );
          })}
        </Dock>
      </div>
    </div>
  );
};

export default Home;
